		path.addLine(to: CGPoint(x: frame.minX + 0.31532 * frame.width, y: frame.minY + 0.47949 * frame.height))
		path.closeSubpath()
		path.move(to: CGPoint(x: frame.minX + 0.63056 * frame.width, y: frame.minY + 0.68615 * frame.height))
