		return path
	}
}

struct Grid16yLine: Shape {
	func path(in rect: CGRect) -> Path {
		
		var path = Path()
		let frame: CGRect = rect.fitRect(ratio: 1.0)
		
			//// Bezier 17 Drawing
		path.move(to: CGPoint(x: frame.minX + 0.10520 * frame.width, y: frame.minY + -0.00000 * frame.height))
		path.addLine(to: CGPoint(x: frame.minX + 0.10520 * frame.width, y: frame.minY + 0.97167 * frame.height))
		path.move(to: CGPoint(x: frame.minX + 0.42042 * frame.width, y: frame.minY + -0.00000 * frame.height))
		path.addLine(to: CGPoint(x: frame.minX + 0.42042 * frame.width, y: frame.minY + 0.97167 * frame.height))
		path.move(to: CGPoint(x: frame.minX + 0.58217 * frame.width, y: frame.minY + -0.00000 * frame.height))
		path.addLine(to: CGPoint(x: frame.minX + 0.58217 * frame.width, y: frame.minY + 0.97167 * frame.height))
		path.move(to: CGPoint(x: frame.minX + 0.89739 * frame.width, y: frame.minY + -0.00000 * frame.height))
		path.addLine(to: CGPoint(x: frame.minX + 0.89739 * frame.width, y: frame.minY + 0.97167 * frame.height))
		
		return path
	}
}

